import { calculateDiscount, Customer } from "./calculateDiscount";

// Fixed reference date for all tests — keeps assertions deterministic
const NOW = new Date("2024-06-01T00:00:00.000Z");

function daysAgo(days: number): Date {
  return new Date(NOW.getTime() - days * 24 * 60 * 60 * 1000);
}

// ---------------------------------------------------------------------------
// AC1: New customer (account age < 30 days) → 5%
// ---------------------------------------------------------------------------
describe("AC1: new customer discount", () => {
  it("returns 5% when account is 0 days old (just created)", () => {
    const customer: Customer = {
      accountCreatedAt: NOW,
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });

  it("returns 5% when account is 1 day old", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(1),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });

  it("returns 5% when account is 29 days old (boundary: still new)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(29),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });

  it("returns 5% even if a new customer has made purchases", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(10),
      purchases: [daysAgo(5), daysAgo(2)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });

  it("ignores tier for new customers — premium tier still gets 5%", () => {
    const customer: Customer = {
      tier: "premium",
      accountCreatedAt: daysAgo(15),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });
});

// ---------------------------------------------------------------------------
// AC2: Returning customer, no purchase in last 90 days → 3% (win-back)
// ---------------------------------------------------------------------------
describe("AC2: returning customer win-back discount", () => {
  it("returns 3% when account is exactly 30 days old with no purchases", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(30),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });

  it("returns 3% when account is 60 days old with no purchase history", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(60),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });

  it("returns 3% when last purchase was exactly 91 days ago (outside 90-day window)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(365),
      purchases: [daysAgo(91), daysAgo(200)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });

  it("returns 3% when purchases exist but all are older than 90 days", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(180),
      purchases: [daysAgo(100), daysAgo(150), daysAgo(180)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });

  it("ignores tier for lapsed returning customers — gold tier still gets 3%", () => {
    const customer: Customer = {
      tier: "gold",
      accountCreatedAt: daysAgo(90),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });
});

// ---------------------------------------------------------------------------
// AC3: Returning customer with purchase in last 90 days → 0%
// ---------------------------------------------------------------------------
describe("AC3: active returning customer — no discount", () => {
  it("returns 0% when account is 30 days old and purchased today", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(30),
      purchases: [NOW],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0);
  });

  it("returns 0% when account is 90 days old and last purchase was 1 day ago", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(90),
      purchases: [daysAgo(1)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0);
  });

  it("returns 0% when last purchase was exactly 90 days ago (boundary: inside window)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(365),
      purchases: [daysAgo(90)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0);
  });

  it("returns 0% when customer has many purchases and the latest is recent", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(200),
      purchases: [daysAgo(180), daysAgo(120), daysAgo(45)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0);
  });

  it("ignores tier for active returning customers — premium tier still gets 0%", () => {
    const customer: Customer = {
      tier: "premium",
      accountCreatedAt: daysAgo(60),
      purchases: [daysAgo(10)],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0);
  });
});

// ---------------------------------------------------------------------------
// Boundary: the 30-day account-age threshold
// ---------------------------------------------------------------------------
describe("boundary: 30-day new/returning threshold", () => {
  it("29 days old with no purchases → new customer (5%), not win-back (3%)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(29),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.05);
  });

  it("30 days old with no purchases → returning customer (3%), not new (5%)", () => {
    const customer: Customer = {
      accountCreatedAt: daysAgo(30),
      purchases: [],
    };
    expect(calculateDiscount(customer, NOW)).toBe(0.03);
  });
});

